func newUserService() *userService {
	return &userService{
		users: make(map[string]*User),
	}
}

func (s *userService) CreateUser(ctx context.Context, req *CreateUserRequest) (*User, error) {
	user := &User{
		Id:       generateID(),
		Username: req.Username,
		Email:    req.Email,
		FullName: req.FullName,
	}
	s.users[user.Id] = user
	log.Printf("User created: %s", user.Id)
	return user, nil
}

func (s *userService) GetUser(ctx context.Context, req *GetUserRequest) (*User, error) {
	user, exists := s.users[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "user not found")
	}
	return user, nil
}

func (s *userService) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*User, error) {
	user, exists := s.users[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "user not found")
	}
	user.Username = req.Username
	user.Email = req.Email
	user.FullName = req.FullName
	log.Printf("User updated: %s", user.Id)
	return user, nil
}

func (s *userService) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*DeleteUserResponse, error) {
	if _, exists := s.users[req.Id]; !exists {
		return nil, status.Errorf(codes.NotFound, "user not found")
	}
	delete(s.users, req.Id)
	log.Printf("User deleted: %s", req.Id)
	return &DeleteUserResponse{Success: true}, nil
}

type orderService struct {
	UnimplementedOrderServiceServer
	orders map[string]*Order
}

func newOrderService() *orderService {
	return &orderService{
		orders: make(map[string]*Order),
	}
}

func (s *orderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	order := &Order{
		Id:         generateID(),
		UserId:     req.UserId,
		TotalPrice: req.TotalPrice,
		Status:     "pending",
	}
	s.orders[order.Id] = order
	log.Printf("Order created: %s", order.Id)
	return order, nil
}

func (s *orderService) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	order, exists := s.orders[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "order not found")
	}
	return order, nil
}

func (s *orderService) UpdateOrderStatus(ctx context.Context, req *UpdateOrderStatusRequest) (*Order, error) {
	order, exists := s.orders[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "order not found")
	}
	order.Status = req.Status
	log.Printf("Order status updated: %s -> %s", order.Id, req.Status)
	return order, nil
}

func (s *orderService) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*CancelOrderResponse, error) {
	order, exists := s.orders[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "order not found")
	}
	order.Status = "cancelled"
	log.Printf("Order cancelled: %s", req.Id)
	return &CancelOrderResponse{Success: true}, nil
}

type paymentService struct {
	UnimplementedPaymentServiceServer
	payments map[string]*Payment
}

func newPaymentService() *paymentService {
	return &paymentService{
		payments: make(map[string]*Payment),
	}
}

func (s *paymentService) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*Payment, error) {
	payment := &Payment{
		Id:            generateID(),
		OrderId:       req.OrderId,
		Amount:        req.Amount,
		Status:        "completed",
		PaymentMethod: req.PaymentMethod,
	}
	s.payments[payment.Id] = payment
	log.Printf("Payment processed: %s", payment.Id)
	return payment, nil
}

func (s *paymentService) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	payment, exists := s.payments[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "payment not found")
	}
	return payment, nil
}

func (s *paymentService) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*RefundPaymentResponse, error) {
	payment, exists := s.payments[req.Id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "payment not found")
	}
	payment.Status = "refunded"
	log.Printf("Payment refunded: %s", req.Id)
	return &RefundPaymentResponse{Success: true}, nil
}

func generateID() string {
	return "id_" + string(rune(len(descriptorpb.File_google_protobuf_descriptor_proto.String())))
}

func main() {
	listener, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("Failed to listen: %v", err)
	}

	grpcServer := grpc.NewServer()

	RegisterUserServiceServer(grpcServer, newUserService())
	RegisterOrderServiceServer(grpcServer, newOrderService())
	RegisterPaymentServiceServer(grpcServer, newPaymentService())

	reflection.Register(grpcServer)

	log.Println("gRPC server with reflection enabled listening on :50051")
	log.Println("Services registered: UserService, OrderService, PaymentService")
	log.Println("Use grpcurl or similar tools to discover services")

	if err := grpcServer.Serve(listener); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}